image = imread(fullpath(getIPCVpath() + "/images/opencv_left01.jpg"));
features = imdetect_ORB(image, 500);
marked = imdrawkeypoints(image, features, [255 0 0]);
imshow(marked);

image = imread(fullpath(getIPCVpath() + "/images/opencv_smarties.png"));
features = imdetect_AKAZE(image);
marked = imdrawkeypoints(image, features, [0 255 0]);
imshow(marked);
